import boto3

job_name = "sagemaker-demo-stock-price-job"
role = "arn:aws:iam::aws:role/service-role/AmazonSageMaker-ExecutionRole-20200720T202051"

dataprocessing = boto3.client('sagemaker')

response = dataprocessing.create_processing_job(
    ProcessingInputs=[{
        'InputName': 'stock_data',
        'S3Input': {
            'S3Uri': 's3://stock-data-bucket/data',
            'LocalPath': '/opt/ml/processing/input'
        }
    }],
    ProcessingOutputConfig={
        'Outputs': [{
            'OutputName': 'stock_data_processed',
            'S3Output': {
                'S3Uri': 's3://stock-data-bucket/processed-data',
                'LocalPath': '/opt/ml/processing/output'
            }
        }],
        'KmsKeyId': 'aws/sagemaker'
    },
    ProcessingJobName=job_name,
    ProcessingResources={
        'ClusterConfig': {
            'InstanceCount': 1,
            'InstanceType': 'ml.m5.xlarge',
            'VolumeSizeInGB': 30
        }
    },
    StoppingCondition={
        'MaxRuntimeInSeconds': 1800
    },
    AppSpecification={
        'ImageUri': '732703918919.dkr.ecr.us-east-1.amazonaws.com/sagemaker-stock-price-model:1.0.0',
	'ContainerEntrypoint': [
            'python3',
            '/opt/ml/processing/train.py'
        ]
    },
    Environment={
        'MaxRuntimeInSeconds': 1800,
        'ResourceConfig': {
            'VolumeKmsKeyId': 'aws/sagemaker'
        }
    },
    RoleArn=role
)
